import json
import re
# var_call_WqLPOlqLdhIS7WJIJqCStrj0 and var_call_aMPyEbMFI8LDZjx9UqQr55DN are available from storage
reviews = var_call_WqLPOlqLdhIS7WJIJqCStrj0
business_docs = var_call_aMPyEbMFI8LDZjx9UqQr55DN

# Build mapping from business_ref to count
ref_counts = {}
for r in reviews:
    ref = r['business_ref']
    try:
        cnt = int(r['cnt'])
    except:
        cnt = 0
    ref_counts[ref] = cnt

# Map to business_id
ref_to_bid = {ref: ref.replace('businessref_', 'businessid_') for ref in ref_counts}
all_bids = set(ref_to_bid.values())

# Build business_id -> description mapping from fetched docs
bid_to_doc = {d['business_id']: d for d in business_docs}

# Identify missing business_ids
missing_bids = sorted(list(all_bids - set(bid_to_doc.keys())))

# Function to extract categories from description
def extract_categories(desc):
    if not desc:
        return []
    # try to find ' in ' and take substring after it up to first period
    m = re.search(r" in (.+?)(?:\.|$)", desc)
    if m:
        cat_str = m.group(1)
    else:
        # fallback: maybe 'in the categories of X, Y' or 'in the fields of X, Y'
        m2 = re.search(r"(?:categories of|fields of|in the categories of|in the fields of) (.+?)(?:\.|$)", desc)
        if m2:
            cat_str = m2.group(1)
        else:
            cat_str = desc
    # split by commas, ' and ', ' & '
    parts = re.split(r",| and | & |, and |;|\band\b", cat_str)
    cats = [p.strip() for p in parts if p.strip()]
    # further split elements containing '/' or '|' or ' - '
    final = []
    for c in cats:
        sub = re.split(r"/|\|| - |: ", c)
        for s in sub:
            s2 = s.strip().rstrip('.')
            if s2:
                final.append(s2)
    return final

# Aggregate counts per category for businesses we have
cat_counts = {}
covered_refs = []
for ref, cnt in ref_counts.items():
    bid = ref_to_bid[ref]
    if bid in bid_to_doc:
        desc = bid_to_doc[bid].get('description', '')
        cats = extract_categories(desc)
        if not cats:
            # if no categories parsed, use business name as category placeholder
            cats = [bid_to_doc[bid].get('name','')]
        for c in cats:
            cat_counts[c] = cat_counts.get(c, 0) + cnt
        covered_refs.append(ref)

# Prepare sorted category totals
sorted_cats = sorted(cat_counts.items(), key=lambda x: x[1], reverse=True)

result = {
    'top_categories_counts': sorted_cats,
    'top_10': sorted_cats[:10],
    'missing_business_ids': missing_bids,
    'total_businesses_in_reviews': len(ref_counts),
    'covered_businesses': len(covered_refs)
}

print("__RESULT__:")
print(json.dumps(result))

